import React, { useState, useEffect } from 'react';
import {
  Container,
  Paper,
  Typography,
  Box,
  Button,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Chip,
  IconButton,
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Alert,
  CircularProgress,
  Card,
  CardContent,
  Grid,
  Tabs,
  Tab,
  Accordion,
  AccordionSummary,
  AccordionDetails,
  Tooltip,
  Divider
} from '@mui/material';
import {
  ListAlt as ListIcon,
  Refresh as RefreshIcon,
  ExpandMore as ExpandMoreIcon,
  Security as SecurityIcon,
  CheckCircle as ValidIcon,
  Warning as WarningIcon,
  Error as ErrorIcon,
  Upload as UploadIcon,
  Visibility as ViewIcon,
  Flag as FlagIcon
} from '@mui/icons-material';

const MasterListViewer = () => {
  const [masterLists, setMasterLists] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [selectedCert, setSelectedCert] = useState(null);
  const [certDialogOpen, setCertDialogOpen] = useState(false);
  const [tabValue, setTabValue] = useState(0);

  const fetchMasterLists = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await fetch('/api/admin/master-lists');
      if (!response.ok) throw new Error('Failed to fetch master lists');
      const data = await response.json();
      setMasterLists(data.masterLists || []);
    } catch (err) {
      // Use sample data for demo purposes
      setMasterLists([
        {
          country: "FRA",
          sequenceNumber: 33,
          version: "1.0.0",
          issueDate: "2025-10-04T00:43:13.053013+00:00",
