            },
            {
              certificateId: "FRA_CSCA_4",
              thumbprint: "cc0bdc1863719e890094c89eebdd98f9156d1be2",
              subject: "CN=FRA CSCA 4, O=FRA Government, C=FRA",
              validFrom: "2024-11-06T00:43:13.053007+00:00",
